const animals = [
  ["cat","貓","suburb",-43,-38,"牠躲在屋旁，表情像是已經付過租金。"],["dog","小狗","suburb",-28,-36,"牠正在等一位也許迷路了的小主人。"],["bee","蜜蜂","suburb",-45,-19,"忙碌得像一顆會飛的小太陽。"],["parrot","小鳥","suburb",-20,-44,"牠把消防車的聲音學得不太像。"],
  ["deer","鹿","forest",23,24,"牠在林緣張望，耳朵比風更早轉彎。"],["fox","狐狸","forest",42,31,"牠踩著自己的影子，走得很有禮貌。"],["bunny","兔子","forest",22,45,"牠相信所有蘑菇旁邊都值得停一下。"],["panda","熊貓","forest",40,48,"今天的行程只有一項：慢慢吃。"],["beaver","河狸","forest",50,19,"牠正在研究水車，似乎想提出改良方案。"],["bee","蜜蜂","forest",32,37,"牠在花叢間巡迴，從不漏掉任何一朵。"],["penguin","企鵝","forest",51,48,"牠站在一小片雪旁，堅稱這裡很涼。"],["koala","無尾熊","forest",17,36,"牠把樹當成一張垂直的床。"],["polar","小白熊","forest",47,42,"牠正和企鵝討論哪裡比較像冬天。"],["cat","墓園睡貓","graveyard",-26,37,"牠在墓碑旁睡得很熟，神秘感暫停營業。"]
].map(([id,name,zone,x,z,text],i)=>({id:`${id}-${i}`,species:id,name,zone,x,z,text,model:`characters/animals/cube-pets/animal-${id}.glb`}));
const npcs = [
  ["post","郵差阿信","迷路郵差","suburb",-38,-28,"human","我手上有三封信、四個門牌，還有一點點方向感。你知道風車街七號在哪嗎？","我替你看看。","太好了！如果找到八號也別告訴我，我怕工作突然變多。"],
  ["kid","小晴","找狗的小孩","suburb",-24,-39,"human2","我的小狗叫豆豆。牠會追尾巴，但通常追不到很遠。你看見牠嗎？","屋邊好像有腳印。","那一定是牠！也可能是貓，但我先保持樂觀。"],
  ["taxi","林叔","候客的士司機","suburb",-46,-45,"human","我在等一位說「兩分鐘到」的乘客。那是二十分鐘前的事。","要不要先喝杯茶？","好主意。計程錶不走，茶可以走。"],
  ["fire","阿焰","消防員","suburb",-17,-23,"human2","放心，沒有火警。我只是來確認這個消防栓是不是仍然很紅。","結論如何？","非常紅。今天的檢查圓滿完成。"],
  ["mira","米拉","寶石商人","market",-37,22,"oodi","這顆寶石在月光下會發亮，在陽光下也會——其實它一直都很努力。","它有甚麼用途？","提醒你：漂亮本身偶爾也算一種用途。"],
  ["baker","麥叔","風車麵包師","market",-19,39,"human","我把風車鑰匙放在「最安全的地方」，現在連我也找不到。","我沿路留意。","謝謝。聞到麵包香時往左，聞不到時也可以往左。"],
  ["story","露露","噴泉旅人","market",-40,40,"oobi","大家圍著噴泉交換故事。我的故事很短：我走錯路，然後來到好地方。","這故事不錯。","謝謝！錯路通常比對的路更會說故事。"],
  ["miller","洛奇","水車觀察員","market",-15,18,"human2","可以替我看看水車還有沒有轉嗎？我盯太久，現在連山也像在轉。","我去看看。","慢慢走。水車不會逃跑，至少今天不會。"],
  ["ranger","青木","高地巡林員","forest",27,17,"human","這裡的動物很多。請小聲一點，企鵝正在假裝自己很合群。","我會放輕腳步。","謝謝。狐狸會記住有禮貌的鞋子。"],
  ["keeper","守墓人阿柏","守墓人","graveyard",-44,20,"keeper","你有看到一把鏟子嗎？它原本靠著長椅。至少我記得那是鏟子，不是很安靜的骷髏。","我替你留意。","感謝。它如果自己走回來，請先問它去了哪裡。"],
  ["bones","骨哥","忘事骷髏","graveyard",-22,27,"skeleton","我忘了原本坐哪張長椅。好消息是，我坐哪張都不會腰酸。","這張看來不錯。","有眼光。雖然我沒有。"],
  ["boo","小飄","市集迷幽靈","graveyard",-43,45,"ghost","市集今天熱鬧嗎？我一去，大家就說氣氛突然涼快了。","噴泉旁很熱鬧。","太好了！我會帶一點陰風當伴手禮。"],
  ["vlad","維拉德","怕亮吸血鬼","graveyard",-17,43,"vampire","墓園的燈是不是太亮？我連自己的神秘輪廓都看得一清二楚。","戴頂帽子呢？","天才。最好是一頂非常有陰影的帽子。"]
].map(([id,name,role,zone,x,z,model,first,choice,reply])=>({id,name,role,zone,x,z,model,first,choice,reply}));
const landmarks = [
  ["hidden-cat","躲貓小屋","suburb",-45,-37,"這棟小屋旁總有一雙鬍鬚悄悄出現。"],["red-check","紅色大檢查","suburb",-15,-22,"消防員確認：今天的消防設施依然非常紅。"],
  ["story-fountain","故事噴泉","market",-40,35,"水聲把旅人的故事攪在一起。"],["lost-key","風車的鑰匙","market",-25,43,"麵包師的安全藏法，成功防住了本人。"],["watermill","還在轉的水車","market",-13,14,"水輪慢悠悠地回答：還在工作。"],
  ["forest-gate","苔痕小門","forest",18,30,"一扇不急著通往任何地方的小門。"],["hill-gem","風頂寶石","forest",43,42,"一顆替高地收藏陽光的寶石。"],["mushroom-ring","蘑菇小會議","forest",27,47,"蘑菇圍成一圈，會議內容嚴格保密。"],
  ["shovel","散步的鏟子","graveyard",-39,29,"它離長椅不遠，只是守墓人的記憶走得更遠。"],["bright-lamp","過亮墓園燈","graveyard",-18,39,"亮得足以讓吸血鬼正式提出意見。"]
].map(([id,name,zone,x,z,text])=>({id,name,zone,x,z,text}));
const zoneData={suburb:{name:"晨光郊區",x:-30,z:-30,color:0xa8d88e,sky:0x8dced3},market:{name:"奇幻市集",x:-30,z:30,color:0xe7b76c,sky:0x9fcfc6},forest:{name:"林間高地",x:30,z:30,color:0x70b878,sky:0x91c9bf},graveyard:{name:"暮色墓園",x:30,z:-30,color:0x7775a1,sky:0x7f8eb2}};
const journalCatalog={zones:Object.entries(zoneData).map(([id,v])=>({id,name:v.name,sub:"到訪區域"})),animals:[...new Map(animals.map(a=>[a.species,{id:a.species,name:a.name.replace("墓園睡","")||a.name,sub:"動物觀察"}])).values()],npcs:npcs.map(n=>({id:n.id,name:n.name,sub:n.role})),landmarks:landmarks.map(l=>({id:l.id,name:l.name,sub:"地標與小事件"}))};

let scene,camera,renderer,clock,player,playerVisual,started=false,paused=true,target=null,pending=null,currentZone="suburb",cameraYaw=.72,cameraDistance=24,toastTimer,audioCtx,sound=true;
const loaders={},interactives=[],colliders=[],wanderers=[],groundMeshes=[],keys=new Set(),pointerMap=new Map();
const saved=JSON.parse(localStorage.getItem("wanderworld-progress")||"null")||{zones:[],animals:[],npcs:[],landmarks:[]};
for(const k of Object.keys(journalCatalog)) saved[k] ||= [];
const dom={canvas:$("#world"),loading:$("#loading"),progress:$("#progress-bar"),progressText:$("#progress-text"),welcome:$("#welcome"),start:$("#start"),place:$("#place-card"),placeName:$("#place-name"),hint:$("#hint"),toast:$("#toast"),card:$("#card"),role:$("#card-role"),name:$("#card-name"),text:$("#card-text"),choices:$("#choices"),journal:$("#journal"),context:$("#context"),contextName:$("#context-name")};

function save(){localStorage.setItem("wanderworld-progress",JSON.stringify(saved))}
function discover(type,id,label){if(saved[type].includes(id))return;saved[type].push(id);save();showToast(`${type==="zones"?"新地點":type==="animals"?"新發現":type==="npcs"?"新朋友":"手札新增"}：${label}`);tone(620)}
function showToast(text){dom.toast.textContent=text;dom.toast.classList.add("show");clearTimeout(toastTimer);toastTimer=setTimeout(()=>dom.toast.classList.remove("show"),2600)}
function tone(freq=440){if(!sound)return;try{audioCtx ||= new AudioContext();const o=audioCtx.createOscillator(),g=audioCtx.createGain();o.frequency.value=freq;o.type="sine";g.gain.setValueAtTime(.04,audioCtx.currentTime);g.gain.exponentialRampToValueAtTime(.001,audioCtx.currentTime+.16);o.connect(g).connect(audioCtx.destination);o.start();o.stop(audioCtx.currentTime+.17)}catch{}}
function makeMat(color){return new THREE.MeshLambertMaterial({color,flatShading:true})}
function box(w,h,d,color,x,z,y=h/2){const m=new THREE.Mesh(new THREE.BoxGeometry(w,h,d),makeMat(color));m.position.set(x,y,z);m.receiveShadow=true;m.castShadow=!mobile;scene.add(m);return m}
function zoneAt(x,z){return x<0?(z<0?"suburb":"market"):(z<0?"graveyard":"forest")}
function addCollider(x,z,w,d,kind="solid"){colliders.push({x,z,w,d,kind})}
function blocked(x,z){if(Math.abs(x)>57||Math.abs(z)>57)return true;return colliders.some(c=>{if(c.kind==="water"&&x>5&&x<13&&z>10&&z<20)return false;return Math.abs(x-c.x)<c.w/2+.65&&Math.abs(z-c.z)<c.d/2+.65})}

async function loadModel(key,path=MODEL[key],height=3){try{let base=loaders[path];if(!base){const gltf=await new GLTFLoader().loadAsync(root+path);base=gltf.scene;loaders[path]=base}const obj=base.clone(true);const box3=new THREE.Box3().setFromObject(obj),size=new THREE.Vector3();box3.getSize(size);const s=height/Math.max(size.y,.01);obj.scale.setScalar(s);box3.setFromObject(obj);const center=new THREE.Vector3();box3.getCenter(center);obj.position.y-=box3.min.y;obj.position.x-=center.x;obj.position.z-=center.z;obj.traverse(o=>{if(o.isMesh){o.castShadow=!mobile;o.receiveShadow=true}});return obj}catch(e){console.warn("Model fallback:",path,e);const g=new THREE.Group();g.add(new THREE.Mesh(new THREE.CapsuleGeometry(.45,1,4,8),makeMat(0xf4c96b)));return g}}
async function place(key,x,z,height=3,rot=0,parent=scene){const obj=await loadModel(key,MODEL[key],height);obj.position.x+=x;obj.position.z+=z;obj.rotation.y=rot;parent.add(obj);return obj}
async function placePath(path,x,z,height=1.3,rot=0,parent=scene){const obj=await loadModel(path,path,height);obj.position.x+=x;obj.position.z+=z;obj.rotation.y=rot;parent.add(obj);return obj}
function halo(parent,color=0xffda73){const ring=new THREE.Mesh(new THREE.RingGeometry(.72,.86,20),new THREE.MeshBasicMaterial({color,side:THREE.DoubleSide,transparent:true,opacity:.8}));ring.rotation.x=-Math.PI/2;ring.position.y=.05;parent.add(ring);return ring}
function register(obj,data){obj.userData.interaction=data;obj.traverse(o=>o.userData.interaction=data);interactives.push(obj);halo(obj,data.type==="animal"?0x9be3a2:0xffda73);return obj}

async function buildWorld(){
  for(const [id,z] of Object.entries(zoneData)){const g=new THREE.Mesh(new THREE.PlaneGeometry(58,58),makeMat(z.color));g.rotation.x=-Math.PI/2;g.position.set(z.x,0,z.z);g.userData.ground=true;scene.add(g);groundMeshes.push(g)}
  box(5,.06,116,0xeed8a2,0,0,.03);box(116,.06,5,0xeed8a2,0,0,.035);
  const water=new THREE.Mesh(new THREE.PlaneGeometry(12,45),new THREE.MeshLambertMaterial({color:0x5eb9c2,transparent:true,opacity:.82}));water.rotation.x=-Math.PI/2;water.position.set(9,.04,32);scene.add(water);addCollider(9,32,9,45,"water");
  const homes=[[-48,-49,"houseA"],[-32,-48,"houseB"],[-48,-20,"houseC"],[-18,-43,"houseA"]];for(const [x,z,k] of homes){await place(k,x,z,7);addCollider(x,z,10,9)}
  await place("taxi",-46,-41,2.2,Math.PI/2);await place("firetruck",-14,-29,2.8);await place("delivery",-36,-22,2.4,Math.PI/2);for(const p of [[-52,-34],[-32,-20],[-20,-51]])await place("cityTree",...p,5);for(const p of [[-40,-35],[-25,-45],[-18,-18]])await place("planter",...p,1.2);
  for(const [x,z,c] of [[-45,26,0xb66b4f],[-25,25,0x945f49],[-40,48,0xc17b50]]){box(8,5,7,c,x,z);box(9,1,8,0x633f35,x,z,5.4);addCollider(x,z,9,8)}
  await place("stall",-35,19,4);await place("stall2",-20,28,4,Math.PI/2);await place("cart",-45,45,2.4);await place("fountain",-39,35,4);addCollider(-39,35,6,6);await place("windmill",-19,45,9);addCollider(-19,45,7,7);await place("watermill",-5,17,6,Math.PI/2);addCollider(-5,17,5,6);
  for(const p of [[18,18],[20,48],[34,21],[47,31],[50,52],[34,48],[55,17]])await place("tree",...p,5+Math.random()*2);for(const p of [[25,26],[38,38],[45,19]])await place("rock",...p,2);for(const p of [[22,42],[28,45],[35,34]])await place("mushroom",...p,1);for(const p of [[19,23],[31,29],[45,47]])await place("flowers",...p,1);
  box(7,.5,9,0x9a6848,9,15,.3);
  await place("crypt",43,-42,7);addCollider(43,-42,10,9);for(const p of [[18,-48],[28,-38],[40,-20],[52,-28],[20,-18]])await place("deadTree",...p,5);for(const p of [[23,-28],[32,-45],[48,-25],[52,-48],[37,-31]])await place("gravestone",...p,2,Math.random()*.4-.2);await place("bench",25,-23,2.2,Math.PI/2);await place("light",18,-39,4);for(const p of [[30,-18],[46,-19],[52,-40]])await place("pumpkin",...p,1);
  player=new THREE.Group();player.position.set(-31,0,-31);scene.add(player);playerVisual=await loadModel("player",MODEL.player,3.2);player.add(playerVisual);
  for(const n of npcs){const obj=await loadModel(n.model,MODEL[n.model],n.model==="ghost"?2.6:3);obj.position.set(n.x,0,n.z);scene.add(obj);register(obj,{type:"npc",...n});wanderers.push({obj,base:new THREE.Vector3(n.x,0,n.z),phase:Math.random()*10,kind:"npc"})}
  for(const a of animals){const obj=await loadModel(a.model,a.model,a.species==="bee"?1.1:1.5);obj.position.set(a.x,a.species==="bee"?.9:0,a.z);scene.add(obj);register(obj,{type:"animal",...a});wanderers.push({obj,base:new THREE.Vector3(a.x,obj.position.y,a.z),phase:Math.random()*10,kind:"animal",shy:["bunny","deer","fox"].includes(a.species)})}
  const lmModel={"hidden-cat":"planter","red-check":"button","story-fountain":"fountain","lost-key":"key","watermill":"watermill","forest-gate":"door","hill-gem":"jewel","mushroom-ring":"mushroom","shovel":"shovel","bright-lamp":"light"};
  for(const l of landmarks){const obj=await loadModel(lmModel[l.id],MODEL[lmModel[l.id]],l.id==="watermill"?1.2:l.id==="bright-lamp"?1.2:1.4);obj.position.set(l.x,0,l.z);scene.add(obj);register(obj,{type:"landmark",...l})}
}

function openCard(data,node=0){paused=true;target=null;pending=null;dom.card.classList.remove("hidden");dom.journal.classList.add("hidden");dom.role.textContent=data.type==="npc"?data.role:data.type==="animal"?`動物觀察 · ${zoneData[data.zone].name}`:"旅途小發現";dom.name.textContent=data.name;dom.choices.innerHTML="";
  if(data.type==="npc"){discover("npcs",data.id,data.name);dom.text.textContent=node?data.reply:data.first;const b=document.createElement("button");b.textContent=node?"繼續散步":"「"+data.choice+"」";b.onclick=()=>node?closePanels():openCard(data,1);dom.choices.append(b)}else{discover(data.type==="animal"?"animals":"landmarks",data.type==="animal"?data.species:data.id,data.name);dom.text.textContent=data.text;const b=document.createElement("button");b.textContent="記進手札，繼續散步";b.onclick=closePanels;dom.choices.append(b)}tone(520)}
function closePanels(){dom.card.classList.add("hidden");dom.journal.classList.add("hidden");paused=!started}
function beginInteraction(data,obj){pending={data,obj};const p=obj.position.clone(),dir=player.position.clone().sub(p).setY(0).normalize();target=p.add(dir.multiplyScalar(2.8));target.y=0}
function nearestInteraction(){let best=null,d=4;for(const obj of interactives){const n=player.position.distanceTo(obj.position);if(n<d){d=n;best=obj}}return best}
function renderJournal(tab="zones"){paused=true;target=null;dom.card.classList.add("hidden");dom.journal.classList.remove("hidden");$("#journal-summary").innerHTML=Object.entries({zones:"地點",animals:"動物",npcs:"朋友",landmarks:"發現"}).map(([k,n])=>`<span><b>${saved[k].length}</b><small>${n}</small></span>`).join("");$("#journal-tabs").innerHTML=Object.entries({zones:"地點",animals:"動物",npcs:"朋友",landmarks:"地標"}).map(([k,n])=>`<button class="${k===tab?"active":""}" data-tab="${k}">${n} ${saved[k].length}/${journalCatalog[k].length}</button>`).join("");$("#journal-list").innerHTML=journalCatalog[tab].map(i=>`<article class="${saved[tab].includes(i.id)?"":"locked"}"><i>${saved[tab].includes(i.id)?"✦":"?"}</i><div><b>${saved[tab].includes(i.id)?i.name:"尚未發現"}</b><small>${saved[tab].includes(i.id)?i.sub:"繼續沿小路探索"}</small></div></article>`).join("");document.querySelectorAll("[data-tab]").forEach(b=>b.onclick=()=>renderJournal(b.dataset.tab))}
function updateZone(){const z=zoneAt(player.position.x,player.position.z);if(z===currentZone)return;currentZone=z;dom.placeName.textContent=zoneData[z].name;dom.place.className=`place-card ${z}`;scene.background=new THREE.Color(zoneData[z].sky);scene.fog.color.copy(scene.background);discover("zones",z,zoneData[z].name)}
function movePlayer(dt){if(paused)return;let move=new THREE.Vector3();if(keys.has("w")||keys.has("arrowup"))move.z-=1;if(keys.has("s")||keys.has("arrowdown"))move.z+=1;if(keys.has("a")||keys.has("arrowleft"))move.x-=1;if(keys.has("d")||keys.has("arrowright"))move.x+=1;if(move.lengthSq()){target=null;move.normalize().applyAxisAngle(new THREE.Vector3(0,1,0),cameraYaw);move.multiplyScalar(7*dt)}else if(target){move.copy(target).sub(player.position);const dist=move.length();if(dist<.18){target=null;if(pending){const p=pending;pending=null;openCard(p.data)}return}move.normalize().multiplyScalar(Math.min(7*dt,dist))}if(move.lengthSq()){const nx=player.position.x+move.x,nz=player.position.z+move.z;if(!blocked(nx,nz)){player.position.x=nx;player.position.z=nz}player.rotation.y=Math.atan2(move.x,move.z);playerVisual.position.y=(reducedMotion?0:Math.abs(Math.sin(clock.elapsedTime*9))*.09);playerVisual.rotation.z=(reducedMotion?0:-move.x*.04)}updateZone()}
function updateCamera(dt){const off=new THREE.Vector3(Math.sin(cameraYaw)*cameraDistance,cameraDistance*.68,Math.cos(cameraYaw)*cameraDistance);const desired=player.position.clone().add(off),ease=1-Math.pow(.002,dt);camera.position.lerp(desired,ease);const look=player.position.clone().add(new THREE.Vector3(0,2,0));camera.lookAt(look)}
function animate(){requestAnimationFrame(animate);const dt=Math.min(clock.getDelta(),.05);movePlayer(dt);updateCamera(dt);if(started&&!paused){for(const w of wanderers){if(w.obj.position.distanceTo(player.position)>28)continue;const t=clock.elapsedTime+w.phase;if(w.kind==="animal"){w.obj.position.x=w.base.x+Math.sin(t*.4)*.65;w.obj.position.z=w.base.z+Math.cos(t*.35)*.45;w.obj.rotation.y=Math.atan2(Math.cos(t*.4),-Math.sin(t*.35));if(w.obj.position.distanceTo(player.position)<5)w.obj.lookAt(player.position.x,w.obj.position.y,player.position.z)}else w.obj.rotation.y+=Math.sin(t)*.0008}}
  renderer.render(scene,camera)}
function resize(){camera.aspect=innerWidth/innerHeight;camera.updateProjectionMatrix();renderer.setSize(innerWidth,innerHeight);renderer.setPixelRatio(Math.min(devicePixelRatio,mobile?1.35:1.8))}

function handleTap(x,y){if(!dom.card.classList.contains("hidden")||!dom.journal.classList.contains("hidden")){closePanels();return}const rect=dom.canvas.getBoundingClientRect(),mouse=new THREE.Vector2((x-rect.left)/rect.width*2-1,-(y-rect.top)/rect.height*2+1),ray=new THREE.Raycaster();ray.setFromCamera(mouse,camera);const hits=ray.intersectObjects(interactives,true);if(hits.length){const data=hits[0].object.userData.interaction,obj=interactives.find(i=>i.userData.interaction===data);beginInteraction(data,obj);return}const ground=ray.intersectObjects(groundMeshes);if(ground.length){const p=ground[0].point;if(!blocked(p.x,p.z)){target=p;pending=null;tone(320);const marker=document.createElement("div");marker.className="flash-marker";marker.style.left=x-12+"px";marker.style.top=y-12+"px";$("#game").append(marker);setTimeout(()=>marker.remove(),850)}}}
function setupInput(){let startPt=null,drag=false,last=null,pinch=0;dom.canvas.addEventListener("pointerdown",e=>{dom.canvas.setPointerCapture(e.pointerId);pointerMap.set(e.pointerId,{x:e.clientX,y:e.clientY});startPt={x:e.clientX,y:e.clientY};last={...startPt};drag=false});dom.canvas.addEventListener("pointermove",e=>{if(!pointerMap.has(e.pointerId))return;pointerMap.set(e.pointerId,{x:e.clientX,y:e.clientY});const pts=[...pointerMap.values()];if(pts.length===2){const d=Math.hypot(pts[0].x-pts[1].x,pts[0].y-pts[1].y);if(pinch)cameraDistance=THREE.MathUtils.clamp(cameraDistance+(pinch-d)*.045,12,34);pinch=d;drag=true}else if(last){const dx=e.clientX-last.x,dy=e.clientY-last.y;if(Math.hypot(e.clientX-startPt.x,e.clientY-startPt.y)>7)drag=true;if(drag){cameraYaw-=dx*.009;dom.canvas.classList.add("dragging")}last={x:e.clientX,y:e.clientY}}});const end=e=>{pointerMap.delete(e.pointerId);if(!drag&&startPt)handleTap(e.clientX,e.clientY);if(pointerMap.size<2)pinch=0;if(!pointerMap.size){startPt=last=null;dom.canvas.classList.remove("dragging")}};dom.canvas.addEventListener("pointerup",end);dom.canvas.addEventListener("pointercancel",end);dom.canvas.addEventListener("wheel",e=>{e.preventDefault();cameraDistance=THREE.MathUtils.clamp(cameraDistance+e.deltaY*.018,12,34)},{passive:false});addEventListener("keydown",e=>{const k=e.key.toLowerCase();keys.add(k);if(k==="escape")closePanels();if(k==="e"){const obj=nearestInteraction();if(obj)beginInteraction(obj.userData.interaction,obj)}});addEventListener("keyup",e=>keys.delete(e.key.toLowerCase()));addEventListener("resize",resize);document.querySelectorAll("[data-close]").forEach(b=>b.onclick=closePanels);$("#journal-btn").onclick=()=>renderJournal();$("#sound-btn").onclick=e=>{sound=!sound;e.currentTarget.textContent=sound?"♬":"♩";tone(500)};$("#reset-btn").onclick=()=>{if(confirm("清除手札並回到旅程起點？")){localStorage.removeItem("wanderworld-progress");location.reload()}}}
async function init(){try{scene=new THREE.Scene();scene.background=new THREE.Color(zoneData.suburb.sky);scene.fog=new THREE.Fog(scene.background,50,115);camera=new THREE.PerspectiveCamera(45,innerWidth/innerHeight,.1,180);renderer=new THREE.WebGLRenderer({canvas:dom.canvas,antialias:!mobile,powerPreference:"high-performance"});renderer.outputColorSpace=THREE.SRGBColorSpace;renderer.shadowMap.enabled=!mobile;renderer.shadowMap.type=THREE.PCFSoftShadowMap;clock=new THREE.Clock();scene.add(new THREE.HemisphereLight(0xeef8ff,0x6f7049,2.1));const sun=new THREE.DirectionalLight(0xfff1cb,2.4);sun.position.set(-35,55,-25);sun.castShadow=!mobile;sun.shadow.mapSize.set(1024,1024);sun.shadow.camera.left=-65;sun.shadow.camera.right=65;sun.shadow.camera.top=65;sun.shadow.camera.bottom=-65;scene.add(sun);resize();let pct=8;const timer=setInterval(()=>{pct=Math.min(88,pct+3);dom.progress.style.width=pct+"%";dom.progressText.textContent=`正在安放沿途風景… ${pct}%`},110);await buildWorld();clearInterval(timer);dom.progress.style.width="100%";dom.progressText.textContent="地圖準備好了 · 100%";setupInput();animate();setTimeout(()=>{dom.loading.classList.add("hidden");dom.welcome.classList.remove("hidden")},350);dom.start.onclick=()=>{dom.welcome.classList.add("hidden");started=true;paused=false;discover("zones","suburb",zoneData.suburb.name);setTimeout(()=>dom.hint.classList.add("hidden"),5000)}}catch(e){console.error(e);$("#error").classList.remove("hidden");dom.loading.classList.add("hidden")}}
init();
